/**
 * Analytics route handlers — framework-agnostic HTTP-layer implementations.
 *
 * This project has no HTTP framework dependency (no Express, Fastify, etc.),
 * so these handlers are plain functions that accept parsed request parameters
 * and return a typed `HandlerResult<T>`. A thin adapter wires them to any
 * HTTP framework:
 *
 *   // Express example:
 *   app.get('/api/analytics/dashboard', (req, res) => {
 *     const result = getDashboardHandler(analyticsService, {
 *       startDate: req.query.startDate as string,
 *       endDate: req.query.endDate as string,
 *     });
 *     res.status(result.statusCode).json(result.body);
 *   });
 *
 * Route structure:
 *   GET  /api/analytics/dashboard          → full dashboard payload
 *   GET  /api/analytics/metrics/:type      → single metric summary
 *   GET  /api/analytics/metrics/:type/series → time-series for one metric
 *   POST /api/analytics/metrics            → record a new data point
 */

import type {
  AnalyticsQuery,
  CreateMetricRecordInput,
  DashboardData,
  MetricRecord,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TimeSeriesPoint,
} from '../models/analytics.js';
import type { AnalyticsService } from '../services/analytics.service.js';

// ---------------------------------------------------------------------------
// Request / response types for the route layer
// ---------------------------------------------------------------------------

/**
 * Parsed query-string parameters for dashboard and metric endpoints.
 */
export interface DashboardQueryParams {
  startDate: string;
  endDate: string;
  granularity?: TimeGranularity;
}

/**
 * Parsed parameters for single-metric endpoints.
 */
export interface MetricRouteParams {
  metricType: MetricType;
}

/**
 * Standardized error response body.
 */
export interface AnalyticsErrorResponse {
  error: string;
  message: string;
}

/**
 * Typed result returned by every handler. The adapter maps `statusCode`
 * to the HTTP response and serializes `body` as JSON.
 */
export type HandlerResult<T> = {
  statusCode: number;
  body: T | AnalyticsErrorResponse;
};

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

const VALID_METRIC_TYPES: ReadonlySet<string> = new Set<MetricType>([
  'orders_count',
  'revenue',
  'average_order_value',
  'active_users',
  'new_users',
]);

const VALID_GRANULARITIES: ReadonlySet<string> = new Set<TimeGranularity>([
  'hour',
  'day',
  'week',
  'month',
]);

/**
 * Validate that a string is a known MetricType.
 */
function isValidMetricType(value: string): value is MetricType {
  return VALID_METRIC_TYPES.has(value);
}

/**
 * Validate that a string is a known TimeGranularity.
 */
function isValidGranularity(value: string): value is TimeGranularity {
  return VALID_GRANULARITIES.has(value);
}

/**
 * Validate that a string parses as a valid ISO-8601 date.
 */
function isValidISODate(value: string): boolean {
  const d = new Date(value);
  return !Number.isNaN(d.getTime());
}

/**
 * Build a 400-level error result.
 */
function validationError(message: string): HandlerResult<never> {
  return { statusCode: 400, body: { error: 'VALIDATION_ERROR', message } };
}

/**
 * Build a 500-level error result.
 */
function internalError(message: string): HandlerResult<never> {
  return { statusCode: 500, body: { error: 'INTERNAL_ERROR', message } };
}

/**
 * Validate and parse dashboard query parameters.
 * Returns either a valid AnalyticsQuery or a HandlerResult with a 400 error.
 */
function parseDashboardQuery(
  params: DashboardQueryParams,
): AnalyticsQuery | HandlerResult<never> {
  if (!params.startDate || !params.endDate) {
    return validationError('startDate and endDate query parameters are required');
  }
  if (!isValidISODate(params.startDate)) {
    return validationError(
      `Invalid startDate "${params.startDate}". Must be a valid ISO-8601 date string`,
    );
  }
  if (!isValidISODate(params.endDate)) {
    return validationError(
      `Invalid endDate "${params.endDate}". Must be a valid ISO-8601 date string`,
    );
  }
  if (new Date(params.endDate) <= new Date(params.startDate)) {
    return validationError('endDate must be after startDate');
  }
  if (params.granularity && !isValidGranularity(params.granularity)) {
    return validationError(
      `Invalid granularity "${params.granularity}". Must be one of: hour, day, week, month`,
    );
  }
  return {
    startDate: params.startDate,
    endDate: params.endDate,
    granularity: params.granularity,
  };
}

/**
 * Type guard: returns true if the parse result is a HandlerResult (error).
 */
function isHandlerResult<T>(
  value: AnalyticsQuery | HandlerResult<T>,
): value is HandlerResult<T> {
  return 'statusCode' in value;
}

// ---------------------------------------------------------------------------
// Route handlers
// ---------------------------------------------------------------------------

/**
 * GET /api/analytics/dashboard
 *
 * Returns the full dashboard payload with all metric summaries.
 */
export function getDashboardHandler(
  service: AnalyticsService,
  params: DashboardQueryParams,
): HandlerResult<DashboardData> {
  const queryOrError = parseDashboardQuery(params);
  if (isHandlerResult(queryOrError)) {
    return queryOrError;
  }
  try {
    const data = service.getDashboard(queryOrError);
    return { statusCode: 200, body: data };
  } catch (err) {
    return internalError(
      err instanceof Error ? err.message : 'Failed to generate dashboard',
    );
  }
}

/**
 * GET /api/analytics/metrics/:type
 *
 * Returns a summary for a single metric type.
 */
export function getMetricSummaryHandler(
  service: AnalyticsService,
  routeParams: MetricRouteParams,
  queryParams: DashboardQueryParams,
): HandlerResult<MetricSummary> {
  if (!isValidMetricType(routeParams.metricType)) {
    return validationError(
      `Invalid metric type "${routeParams.metricType}". Must be one of: ${[...VALID_METRIC_TYPES].join(', ')}`,
    );
  }
  const queryOrError = parseDashboardQuery(queryParams);
  if (isHandlerResult(queryOrError)) {
    return queryOrError;
  }
  try {
    const summary = service.getMetricSummary(routeParams.metricType, queryOrError);
    return { statusCode: 200, body: summary };
  } catch (err) {
    return internalError(
      err instanceof Error ? err.message : 'Failed to get metric summary',
    );
  }
}

/**
 * GET /api/analytics/metrics/:type/series
 *
 * Returns time-series data points for a single metric.
 */
export function getTimeSeriesHandler(
  service: AnalyticsService,
  routeParams: MetricRouteParams,
  queryParams: DashboardQueryParams,
): HandlerResult<TimeSeriesPoint[]> {
  if (!isValidMetricType(routeParams.metricType)) {
    return validationError(
      `Invalid metric type "${routeParams.metricType}". Must be one of: ${[...VALID_METRIC_TYPES].join(', ')}`,
    );
  }
  const queryOrError = parseDashboardQuery(queryParams);
  if (isHandlerResult(queryOrError)) {
    return queryOrError;
  }
  try {
    const series = service.getTimeSeries(routeParams.metricType, queryOrError);
    return { statusCode: 200, body: series };
  } catch (err) {
    return internalError(
      err instanceof Error ? err.message : 'Failed to get time series',
    );
  }
}

/**
 * POST /api/analytics/metrics
 *
 * Record a new metric data point. Used for manual/external metric ingestion.
 */
export function recordMetricHandler(
  service: AnalyticsService,
  body: CreateMetricRecordInput,
): HandlerResult<MetricRecord> {
  if (!body.metricType) {
    return validationError('metricType is required');
  }
  if (!isValidMetricType(body.metricType)) {
    return validationError(
      `Invalid metric type "${body.metricType}". Must be one of: ${[...VALID_METRIC_TYPES].join(', ')}`,
    );
  }
  if (typeof body.value !== 'number' || Number.isNaN(body.value)) {
    return validationError('value must be a valid number');
  }
  if (body.timestamp !== undefined && !isValidISODate(body.timestamp)) {
    return validationError(
      `Invalid timestamp "${body.timestamp}". Must be a valid ISO-8601 date string`,
    );
  }
  try {
    const record = service.recordMetric(body);
    return { statusCode: 201, body: record };
  } catch (err) {
    return internalError(
      err instanceof Error ? err.message : 'Failed to record metric',
    );
  }
}

