import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { EventBus } from '../../src/events/event-bus.js';
import { AnalyticsService, resetMetricIdCounter } from '../../src/services/analytics.service.js';
import {
  getDashboardHandler,
  getMetricSummaryHandler,
  getTimeSeriesHandler,
  recordMetricHandler,
} from '../../src/routes/analytics.routes.js';
import type {
  DashboardData,
  MetricRecord,
  MetricSummary,
  TimeSeriesPoint,
} from '../../src/models/analytics.js';
import type { AnalyticsErrorResponse } from '../../src/routes/analytics.routes.js';

let db: Database;
let repo: AnalyticsRepository;
let eventBus: EventBus;
let service: AnalyticsService;

beforeEach(() => {
  db = new Database();
  repo = new AnalyticsRepository(db);
  eventBus = new EventBus();
  service = new AnalyticsService(repo, eventBus);
  resetMetricIdCounter();
});

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function seedMetrics() {
  service.recordMetric({
    metricType: 'orders_count',
    value: 1,
    timestamp: '2024-03-15T10:00:00.000Z',
  });
  service.recordMetric({
    metricType: 'revenue',
    value: 100,
    timestamp: '2024-03-15T10:00:00.000Z',
  });
  service.recordMetric({
    metricType: 'new_users',
    value: 1,
    timestamp: '2024-03-15T12:00:00.000Z',
  });
}

const VALID_QUERY = {
  startDate: '2024-03-01T00:00:00.000Z',
  endDate: '2024-04-01T00:00:00.000Z',
};

// ---------------------------------------------------------------------------
// getDashboardHandler
// ---------------------------------------------------------------------------

describe('getDashboardHandler', () => {
  it('returns 200 with dashboard data for valid params', () => {
    seedMetrics();
    const result = getDashboardHandler(service, VALID_QUERY);
    expect(result.statusCode).toBe(200);
    const body = result.body as DashboardData;
    expect(body.metrics).toHaveLength(5);
    expect(body.query.startDate).toBe(VALID_QUERY.startDate);
    expect(body.query.endDate).toBe(VALID_QUERY.endDate);
    expect(body.generatedAt).toBeDefined();
  });

  it('returns 400 when startDate is missing', () => {
    const result = getDashboardHandler(service, {
      startDate: '',
      endDate: '2024-04-01T00:00:00.000Z',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.error).toBe('VALIDATION_ERROR');
    expect(body.message).toContain('startDate');
  });

  it('returns 400 when endDate is missing', () => {
    const result = getDashboardHandler(service, {
      startDate: '2024-03-01T00:00:00.000Z',
      endDate: '',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.error).toBe('VALIDATION_ERROR');
  });

  it('returns 400 for invalid startDate', () => {
    const result = getDashboardHandler(service, {
      startDate: 'not-a-date',
      endDate: '2024-04-01T00:00:00.000Z',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('startDate');
  });

  it('returns 400 for invalid endDate', () => {
    const result = getDashboardHandler(service, {
      startDate: '2024-03-01T00:00:00.000Z',
      endDate: 'not-a-date',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('endDate');
  });

  it('returns 400 when endDate is before startDate', () => {
    const result = getDashboardHandler(service, {
      startDate: '2024-04-01T00:00:00.000Z',
      endDate: '2024-03-01T00:00:00.000Z',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('endDate must be after startDate');
  });

  it('returns 400 for invalid granularity', () => {
    const result = getDashboardHandler(service, {
      ...VALID_QUERY,
      granularity: 'year' as any,
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('granularity');
  });

  it('passes granularity through to the query', () => {
    const result = getDashboardHandler(service, {
      ...VALID_QUERY,
      granularity: 'week',
    });
    expect(result.statusCode).toBe(200);
    const body = result.body as DashboardData;
    expect(body.query.granularity).toBe('week');
  });
});

// ---------------------------------------------------------------------------
// getMetricSummaryHandler
// ---------------------------------------------------------------------------

describe('getMetricSummaryHandler', () => {
  it('returns 200 with metric summary for valid params', () => {
    seedMetrics();
    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      VALID_QUERY,
    );
    expect(result.statusCode).toBe(200);
    const body = result.body as MetricSummary;
    expect(body.metricType).toBe('revenue');
    expect(body.currentValue).toBe(100);
  });

  it('returns 400 for invalid metric type', () => {
    const result = getMetricSummaryHandler(
      service,
      { metricType: 'bogus' as any },
      VALID_QUERY,
    );
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.error).toBe('VALIDATION_ERROR');
    expect(body.message).toContain('bogus');
  });

  it('returns 400 when query params are invalid', () => {
    const result = getMetricSummaryHandler(
      service,
      { metricType: 'revenue' },
      { startDate: '', endDate: '' },
    );
    expect(result.statusCode).toBe(400);
  });
});

// ---------------------------------------------------------------------------
// getTimeSeriesHandler
// ---------------------------------------------------------------------------

describe('getTimeSeriesHandler', () => {
  it('returns 200 with time series for valid params', () => {
    seedMetrics();
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'orders_count' },
      VALID_QUERY,
    );
    expect(result.statusCode).toBe(200);
    const body = result.body as TimeSeriesPoint[];
    expect(body.length).toBeGreaterThan(0);
    expect(body[0].timestamp).toBeDefined();
    expect(body[0].value).toBe(1);
  });

  it('returns 400 for invalid metric type', () => {
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'nope' as any },
      VALID_QUERY,
    );
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('nope');
  });

  it('returns 200 with empty array when no data exists', () => {
    const result = getTimeSeriesHandler(
      service,
      { metricType: 'active_users' },
      VALID_QUERY,
    );
    expect(result.statusCode).toBe(200);
    expect(result.body).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// recordMetricHandler
// ---------------------------------------------------------------------------

describe('recordMetricHandler', () => {
  it('returns 201 with recorded metric for valid input', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 42.5,
    });
    expect(result.statusCode).toBe(201);
    const body = result.body as MetricRecord;
    expect(body.id).toBe('metric-000001');
    expect(body.metricType).toBe('revenue');
    expect(body.value).toBe(42.5);
    expect(body.timestamp).toBeDefined();
    expect(body.metadata).toEqual({});
  });

  it('returns 201 and passes through timestamp and metadata', () => {
    const result = recordMetricHandler(service, {
      metricType: 'new_users',
      value: 1,
      timestamp: '2024-06-01T00:00:00.000Z',
      metadata: { userId: 'u-1' },
    });
    expect(result.statusCode).toBe(201);
    const body = result.body as MetricRecord;
    expect(body.timestamp).toBe('2024-06-01T00:00:00.000Z');
    expect(body.metadata).toEqual({ userId: 'u-1' });
  });

  it('returns 400 for invalid metric type', () => {
    const result = recordMetricHandler(service, {
      metricType: 'bad' as any,
      value: 1,
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('bad');
  });

  it('returns 400 when value is not a number', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 'abc' as any,
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('value');
  });

  it('returns 400 when value is NaN', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: NaN,
    });
    expect(result.statusCode).toBe(400);
  });

  it('returns 400 for invalid timestamp', () => {
    const result = recordMetricHandler(service, {
      metricType: 'revenue',
      value: 10,
      timestamp: 'not-a-date',
    });
    expect(result.statusCode).toBe(400);
    const body = result.body as AnalyticsErrorResponse;
    expect(body.message).toContain('timestamp');
  });

  it('returns 400 when metricType is missing', () => {
    const result = recordMetricHandler(service, {
      metricType: '' as any,
      value: 10,
    });
    expect(result.statusCode).toBe(400);
  });
});

